// 高性能 Install-to-Claim 实现（纯 PWA 安装流程）

(function () {
  "use strict";

  // DOM 元素
  const installBtn = document.getElementById("installBtn");
  const installText = document.getElementById("installText");

  // 状态变量
  let deferredPrompt = null;
  let hasClickedInstall = false;
  let isLoading = false;

  // URL 参数处理
  const urlParams = new URLSearchParams(window.location.search);
  const channel = urlParams.get("chl");

  // 设置渠道
  if (channel && typeof window.setOriginalChannel === "function") {
    window.setOriginalChannel(channel);
  }

  // 埋点：Install Web应用页面显示
  if (typeof window.bytePlusTrack === "function") {
    window.bytePlusTrack("pwa_conv_install_web_show");
    window.bytePlusTrack("web_install_page_show");
    // 广告埋点：Install Web应用页面显示
    window.bytePlusTrack("ad_pwa_conv_install_web_show");
  }

  // 监听 PWA 安装提示
  window.addEventListener("beforeinstallprompt", function (e) {
    e.preventDefault();
    deferredPrompt = e;
  });

  // 检查是否已安装
  function isPWAInstalled() {
    return (
      window.matchMedia("(display-mode: standalone)").matches ||
      window.navigator.standalone === true ||
      document.referrer.includes("android-app://")
    );
  }

  // 开始进度动画
  function startProgress() {
    if (isLoading) return;

    isLoading = true;
    installBtn.classList.remove("breath-animation");
    installBtn.classList.add("loading");
    installText.textContent = "Fast Init...";

    setTimeout(() => {
      installText.textContent = "Active";
      installBtn.classList.add("breath-animation");
      installBtn.classList.remove("loading");
      isLoading = false;
    }, 1500);
  }

  // 处理安装按钮点击
  async function handleInstallClick() {
    if (hasClickedInstall) return;
    hasClickedInstall = true;

    // 埋点：Install Web应用页面按钮点击
    if (typeof window.bytePlusTrack === "function") {
      window.bytePlusTrack("pwa_conv_install_web_clickButton", { scene: "install_page" });
      window.bytePlusTrack("web_install_page_click");
      // 广告埋点：Install Web应用页面按钮点击
      window.bytePlusTrack("ad_pwa_conv_install_web_clickButton");
    }

    // PWA 安装流程
    // 检查 PWA 是否准备安装
    if (deferredPrompt) {
      try {
        // 显示安装提示
        deferredPrompt.prompt();

        // 埋点：Install Web应用弹窗显示
        if (typeof window.bytePlusTrack === "function") {
          window.bytePlusTrack("pwa_conv_install_web_pop_show");
          window.bytePlusTrack("web_install_clip_show");
          // 广告埋点：Install Web应用弹窗显示
          window.bytePlusTrack("ad_pwa_conv_install_web_pop_show");
        }

        // 等待用户响应
        const { outcome } = await deferredPrompt.userChoice;

        if (outcome === "accepted") {
          // 埋点：Install Web应用弹窗按钮点击
          if (typeof window.bytePlusTrack === "function") {
            window.bytePlusTrack("pwa_conv_install_web_pop_clickButton");
            window.bytePlusTrack("web_install_clip_clicked");
            // 广告埋点：Install Web应用弹窗按钮点击
            window.bytePlusTrack("ad_pwa_conv_install_web_pop_clickButton");
          }
        } else {
          // 埋点：用户取消安装
          if (typeof window.bytePlusTrack === "function") {
            window.bytePlusTrack("web_install_dismiss");
          }
        }

        // 清空 deferredPrompt
        deferredPrompt = null;
      } catch (error) {
        console.error("PWA 安装失败:", error);
        // 埋点：安装失败
        if (typeof window.bytePlusTrack === "function") {
          window.bytePlusTrack("web_install_failed");
        }
        hasClickedInstall = false;
      }
    } else if (isPWAInstalled()) {
      // 已安装，直接跳转
      window.location.href = `${window.location.origin}/onboarding` + window.location.search;
    } else {
      // 浏览器不支持或未准备好，显示加载动画
      startProgress();
      hasClickedInstall = false;
    }
  }

  // 事件监听
  if (installBtn) {
    installBtn.addEventListener("click", handleInstallClick);
  }

  // 防止下拉刷新
  let startY = 0;
  document.addEventListener(
    "touchstart",
    function (e) {
      startY = e.touches[0].pageY;
    },
    { passive: true },
  );

  document.addEventListener(
    "touchmove",
    function (e) {
      const y = e.touches[0].pageY;
      if (y > startY && window.scrollY <= 0) {
        e.preventDefault();
      }
    },
    { passive: false },
  );

  // 处理应用安装事件
  window.addEventListener("appinstalled", function () {
    // 埋点：安装成功
    if (typeof window.bytePlusTrack === "function") {
      window.bytePlusTrack("web_install_success");
      // 广告埋点：PWA 安装完成
      window.bytePlusTrack("ad_Installed");
    }
    // 跳转到引导页
    setTimeout(() => {
      window.location.href = `${window.location.origin}/onboarding` + window.location.search;
    }, 1000);
  });
})();
